// Metrics source. Runs on built-in sample numbers so it works out of the box.
// To go live, swap this for a CRM node, a Google Sheets read, or an analytics API - the report below builds itself from whatever numbers land here.
return [{ json: {
  this_week:  { new_leads: 82, qualified: 31, meetings: 14, replies: 46, pipeline: 4200000 },
  last_week:  { new_leads: 74, qualified: 27, meetings: 11, replies: 39, pipeline: 3600000 }
} }];

// Build a clean report with week-over-week arrows. Currency shown in generic units - edit the symbol.
const t = $json.this_week, l = $json.last_week;
const CURRENCY = 'INR '; // EDIT: '$', 'INR ', etc.
const arrow = (now, prev) => { if (now > prev) return '⬆ +' + (now - prev); if (now < prev) return '⬇ ' + (now - prev); return '= 0'; };
const pct = (now, prev) => prev ? Math.round(((now - prev) / prev) * 100) : 0;
const money = n => CURRENCY + (n >= 100000 ? (n/100000).toFixed(1) + 'L' : n.toLocaleString());

const report = [
  '*Weekly Pipeline Report*',
  '',
  `New leads:   ${t.new_leads}   (${arrow(t.new_leads, l.new_leads)}, ${pct(t.new_leads,l.new_leads)}%)`,
  `Qualified:   ${t.qualified}   (${arrow(t.qualified, l.qualified)}, ${pct(t.qualified,l.qualified)}%)`,
  `Replies:     ${t.replies}   (${arrow(t.replies, l.replies)}, ${pct(t.replies,l.replies)}%)`,
  `Meetings:    ${t.meetings}   (${arrow(t.meetings, l.meetings)}, ${pct(t.meetings,l.meetings)}%)`,
  `Pipeline:    ${money(t.pipeline)}   (${pct(t.pipeline,l.pipeline)}% WoW)`,
  '',
  t.meetings > l.meetings ? '✅ Meetings up week over week - keep the winning sequence running.' : '⚠ Meetings down - review list quality and top-performing angle.'
].join('\n');

return [{ json: { report } }];
